const propRadius = 80
const bladeCount = 3
const pitch = 15
const hubRadius = 10
const bladeWidth = 20
const thickness = 4

function main() {
  const hubOuter = cylinder({ radius: hubRadius, height: thickness * 2, segments: 32 })
  const bore = cylinder({ radius: 3.2, height: thickness * 2 + 1, segments: 16 })
  const hub = subtract(hubOuter, bore)
  let blades = []
  for (let i = 0; i < bladeCount; i++) {
    const angle = (i * Math.PI * 2) / bladeCount
    blades.push(translate(
      [Math.cos(angle) * propRadius / 2, Math.sin(angle) * propRadius / 2, 0],
      rotate([0, pitch * Math.PI / 180, angle],
        cuboid({ size: [propRadius, bladeWidth, thickness] })
      )
    ))
  }
  return union(
    colorize([0.12, 0.12, 0.14], hub),
    colorize([0.24, 0.24, 0.28], union(...blades))
  )
}

module.exports = { main }

